class Solution {
public:
    int countLargestGroup(int n) {
        vector<int> sumCount(37, 0);
        int maxSize = 0;
        for (int i = 1; i <= n; i++) {
            int sum = 0;
            int num = i;
            while (num > 0) {
                sum += num % 10;
                num /= 10;
            }
            sumCount[sum]++;
            maxSize = max(maxSize, sumCount[sum]);
        }
        int count = 0;
        for (int i = 0; i < 37; i++) {
            if (sumCount[i] == maxSize) {
                count++;
            }
        }
        return count;
    }
};

